def cache_result(ttl=DEFAULT_CACHE_TTL, prefix=CACHE_PREFIX, key_builder=None):
    """
    Caching decorator for expensive database queries or computations.
    
    Args:
        ttl: Time-to-live in seconds for cached data.
        prefix: Redis key prefix for cached items.
        key_builder: Optional custom function to build cache keys.
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Build cache key
            if key_builder:
                cache_key = f"{prefix}{key_builder(*args, **kwargs)}"
            else:
                # Auto-generate cache key from function name and arguments
                key_parts = [func.__module__, func.__qualname__]
                if args:
                    key_parts.append(str(args))
                if kwargs:
                    key_parts.append(str(sorted(kwargs.items())))
                raw_key = ":".join(key_parts)
                hashed_key = hashlib.md5(raw_key.encode()).hexdigest()
                cache_key = f"{prefix}{func.__qualname__}:{hashed_key}"

            # Try to get from cache
            try:
                cached_data = redis_cached.get(cache_key)
                if cached_data is not None:
                    app.logger.debug(f"Cache HIT for key: {cache_key}")
                    return json.loads(cached_data)
            except (redis.ConnectionError, redis.TimeoutError) as e:
                app.logger.warning(f"Redis cache read error: {e}")

            # Cache miss - execute the function
            app.logger.debug(f"Cache MISS for key: {cache_key}")
            result = func(*args, **kwargs)

            # Store result in cache
            try:
                redis_cached.set(cache_key, json.dumps(result), ex=ttl)
            except (redis.ConnectionError, redis.TimeoutError) as e:
                app.logger.warning(f"Redis cache write error: {e}")

            return result
        
        # Add cache invalidation helper
        def invalidate(*args, **kwargs):
            """Invalidate cached result for given arguments."""
            if key_builder:
                cache_key = f"{prefix}{key_builder(*args, **kwargs)}"
            else:
                key_parts = [func.__module__, func.__qualname__]
                if args:
                    key_parts.append(str(args))
                if kwargs:
                    key_parts.append(str(sorted(kwargs.items())))
                raw_key = ":".join(key_parts)
                hashed_key = hashlib.md5(raw_key.encode()).hexdigest()
                cache_key = f"{prefix}{func.__qualname__}:{hashed_key}"
            try:
                redis_cached.delete(cache_key)
            except (redis.ConnectionError, redis.TimeoutError) as e:
                app.logger.warning(f"Redis cache invalidation error: {e}")

        def invalidate_all():
            """Invalidate all cached results for this function."""
            pattern = f"{prefix}{func.__qualname__}:*"
            try:
                cursor = 0
                while True:
                    cursor, keys = redis_cached.scan(cursor, match=pattern, count=100)
                    if keys:
                        redis_cached.delete(*keys)
                    if cursor == 0:
                        break
            except (redis.ConnectionError, redis.TimeoutError) as e:
                app.logger.warning(f"Redis cache invalidation error: {e}")

        wrapper.invalidate = invalidate
        wrapper.invalidate_all = invalidate_all
        return wrapper
    return decorator


