@app.route('/api/cache/stats', methods=['GET'])
@require_session
def cache_stats():
    """Get Redis cache statistics."""
    try:
        info = redis_client.info()
        dbsize = redis_client.dbsize()

        # Count keys by prefix
        session_keys = len(list(redis_client.scan_iter(match=f"{SESSION_PREFIX}*", count=1000)))
        cache_keys = len(list(redis_client.scan_iter(match=f"{CACHE_PREFIX}*", count=1000)))
        rate_limit_keys = len(list(redis_client.scan_iter(match="rate_limit:*", count=1000)))

        return jsonify({
            "redis_version": info.get("redis_version"),
            "connected_clients": info.get("connected_clients"),
            "used_memory_human": info.get("used_memory_human"),
            "total_keys": dbsize,
            "session_keys": session_keys,
            "cache_keys": cache_keys,
            "rate_limit_keys": rate_limit_keys,
            "keyspace_hits": info.get("keyspace_hits", 0),
            "keyspace_misses": info.get("keyspace_misses", 0),
            "hit_rate": round(
                info.get("keyspace_hits", 0) / 
                max(info.get("keyspace_hits", 0) + info.get("keyspace_misses", 0), 1) * 100, 2
            )
        })
    except redis.ConnectionError:
        return jsonify({"error": "Redis connection failed"}), 503


@app.route('/api/cache/flush', methods=['POST'])
@require_session
def flush_cache():
    """Flush all cache entries (not sessions)."""
    try:
        cursor = 0
        deleted = 0
        while True:
            cursor, keys = redis_cached.scan(cursor, match=f"{CACHE_PREFIX}*", count=100)
            if keys:
                deleted += redis_cached.delete(*keys)
            if cursor == 0:
                break
        return jsonify({
            "message": "Cache flushed",
            "keys_deleted": deleted
        })
    except redis.ConnectionError:
        return jsonify({"error": "Redis connection failed"}), 503


